import React, { createContext, useState, useContext, useEffect } from 'react';

// Création du contexte
const AuthContext = createContext();

// Hook pour utiliser le contexte dans d'autres composants
export const useAuth = () => useContext(AuthContext);

// Fournisseur du contexte
const AuthProvider = ({ children }) => {
  // Initialisation de l'état d'authentification à partir du localStorage
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  useEffect(() => {
    // Vérifiez la présence du token dans le localStorage
    const token = localStorage.getItem('token');
    if (token) {
      setIsAuthenticated(true); // Si un token est présent, l'utilisateur est authentifié
    }
  }, []); // Ce useEffect ne s'exécute qu'une fois lors du montage du composant

  const login = (token) => {
    // Lorsque l'utilisateur se connecte, stocke le token dans le localStorage
    localStorage.setItem('token', token);
    setIsAuthenticated(true); // Met à jour l'état d'authentification
  };

  const logout = () => {
    // Lorsque l'utilisateur se déconnecte, supprime le token du localStorage
    localStorage.removeItem('token');
    setIsAuthenticated(false); // Met à jour l'état d'authentification
  };

  return (
    <AuthContext.Provider value={{ isAuthenticated, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export default AuthProvider;
